// src/screens/TourDetailScreen.js
import React from "react";
import { useLocation, useParams, useNavigate } from "react-router-dom";
import "./TourDetail.css"; // Dùng CSS đẹp bạn đã có

const TourDetailScreen = () => {
  const { tourId } = useParams();
  const { state } = useLocation();
  const tour = state?.tour;
  const navigate = useNavigate();

  if (!tour) {
    return (
      <div className="container">
        <p>Không tìm thấy thông tin chi tiết của tour.</p>
        <button className="btn btn-primary" onClick={() => navigate(-1)}>
          Quay lại
        </button>
      </div>
    );
  }

  return (
    <div className="tour-detail-container">
      <div className="tour-detail-card">
        <div className="tour-image-section">
          <img src={tour.images[0]} alt={tour.title} className="tour-image" />
        </div>

        <div className="tour-info-section">
          <h2 className="tour-title">{tour.title}</h2>
          <p>
            <strong>Địa điểm:</strong> {tour.destination}
          </p>
          <p>
            <strong>Thời gian:</strong> {tour.time}
          </p>
          <p>
            <strong>Số lượng:</strong> {tour.quantity}
          </p>
          <p>
            <strong>Giá:</strong> {tour.priceAdult.toLocaleString("vi-VN")} VND
          </p>
          <p>
            <strong>Đánh giá:</strong> {tour.rating} / 5
          </p>
        </div>
      </div>

      <div className="tour-description">
        <h3>Mô tả</h3>
        <p>{tour.description || "Chưa có mô tả cho tour này."}</p>
      </div>
    </div>
  );
};

export default TourDetailScreen;
